import"./stepper.min.js";import"./search.min.js";import{c as n}from"./cartStore.min.js";import"./common.min.js";import"./cartCounter.min.js";import"./wishlistCounter.min.js";import"./wishlistStore.min.js";function a(){const e=document.querySelector(".cart-content__table");if(document.querySelector(".cart-content__summary span"),!e)return;if(!n.items.length){e.innerHTML=`
  <div class="cart-content__empty">
    Cart is empty
  </div>`;return}const c=n.items.map(t=>`
<div class="cart-content__row" data-id="${t.id}">
  <div class="cart-content__container">
    <div class="cart-content__inner grid">

      <div class="cart-content__cell cart-content__cell--1">
        <picture>
          <img
            class="cart-content__image"
            src="${t.image}"
            alt="${t.title}"
            width="200"
            height="200"
            loading="lazy"
          />
        </picture>
      </div>

      <div class="cart-content__cell cart-content__cell--2">
        <h3 class="cart-content__subtitle">${t.title}</h3>
        <div class="cart-content__quantity--mobile"></div>
      </div>

      <div class="cart-content__cell cart-content__cell--3">
        <div class="cart-content__th cart-content__th--mobile">Price</div>
        <div class="cart-content__price">${t.price}$</div>
      </div>

      <div class="cart-content__cell cart-content__cell--4">
        <div  class="cart-content__quantity">
          <div
            data-fls-stepper
            class="stepper cart-content__stepper"
            role="group"
            aria-label="Quantity selector"
          >
            <button
            class="stepper__minus"
            type="button"
            aria-label="Decrease quantity">
             <img
              class="icon"
              src="./assets/img/minus.svg"
              alt="icon minus"
             />
            </button>

            <input
              type="number"
              name="stepper"
              class="input-reset stepper__input"
              value="${t.qty}"
              min="1"
              max="99"
              inputmode="numeric"
              aria-label="Quantity"
            />

              <button
                type="button"
                class="stepper__plus"
                aria-label="Increase quantity"
              >
               <img
                 class="icon"
                 src="./assets/img/plus.svg"
                 alt="icon plus"
                />
              </button>
                 <span class="visually-hidden" aria-live="polite"></span>
          </div>
        </div>
      </div>

      <div class="cart-content__cell cart-content__cell--5">
        <div class="cart-content__th cart-content__th--mobile">Total</div>

        <div class="cart-content__total">
        ${(t.qty*t.price).toFixed(2)}$
        </div>

        <button
          class="cart-content__remove-button"
          data-remove="${t.id}"
        >
          Remove
        </button>
      </div>

    </div>
  </div>
</div>
`).join("");e.innerHTML=c+`
<div class="cart-content__bottom">
  <a href="order.html" class="button button--primary cart-content__button">
    Proceed to checkout
  </a>

  <div class="cart-content__summary">
    total:<span>${n.total().toFixed(2)}$</span>
  </div>
</div>
`,document.dispatchEvent(new CustomEvent("stepper:init"))}document.addEventListener("cart:update",a),document.addEventListener("click",e=>{const c=e.target.closest("[data-remove]");c&&n.remove(c.dataset.remove)}),a();
